-- Bundled by luabundle {\u0022rootModuleName\u0022:\u0022Epic Wing Token.4cc140.lua\u0022,\u0022version\u0022:\u00221.6.0\u0022}\nlocal __bundle_require, __bundle_loaded, __bundle_register, __bundle_modules = (function(superRequire)\n\tlocal loadingPlaceholder = {[{}] = true}\n\n\tlocal register\n\tlocal modules = {}\n\n\tlocal require\n\tlocal loaded = {}\n\n\tregister = function(name, body)\n\t\tif not modules[name] then\n\t\t\tmodules[name] = body\n\t\tend\n\tend\n\n\trequire = function(name)\n\t\tlocal loadedModule = loaded[name]\n\n\t\tif loadedModule then\n\t\t\tif loadedModule == loadingPlaceholder then\n\t\t\t\treturn nil\n\t\t\tend\n\t\telse\n\t\t\tif not modules[name] then\n\t\t\t\tif not superRequire then\n\t\t\t\t\tlocal identifier = type(name) == \u0027string\u0027 and \u0027\\\u0022\u0027 .. name .. \u0027\\\u0022\u0027 or tostring(name)\n\t\t\t\t\terror(\u0027Tried to require \u0027 .. identifier .. \u0027, but no such module has been registered\u0027)\n\t\t\t\telse\n\t\t\t\t\treturn superRequire(name)\n\t\t\t\tend\n\t\t\tend\n\n\t\t\tloaded[name] = loadingPlaceholder\n\t\t\tloadedModule = modules[name](require, loaded, register, modules)\n\t\t\tloaded[name] = loadedModule\n\t\tend\n\n\t\treturn loadedModule\n\tend\n\n\treturn require, loaded, register, modules\nend)(nil)\n__bundle_register(\u0022Epic Wing Token.4cc140.lua\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\nrequire(\u0022Game.Mechanic.EpicWingGizmo\u0022)\r\n\nend)\n__bundle_register(\u0022Game.Mechanic.EpicWingGizmo\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- ~~~~~~\r\n-- Script by CrazyVulcan\r\n-- Based on work by dzikakulka\r\n-- Issues, history at: TBD\r\n--\r\n-- Epic Wing gizmo token v0.1 test canadate.\r\n-- ~~~~~~\r\n\r\nlocal Dim = require(\u0022Dim\u0022)\r\n\r\n-- Scripted token properties\r\n__XW_Token = true\r\n__XW_TokenIdle = false\r\n__XW_TokenType = \u0027helper:epicWing\u0027\r\n\r\nlocal Vect = require(\u0022TTS_lib.Vector.Vector\u0022)\r\nlocal s1 = 0.73\r\n\r\nwingPositions = {\r\n    leader = {\r\n        posName = \u0022leader\u0022,\r\n        posOffset = vector(0, 0, 0),\r\n    },\r\n    leftFlank = {\r\n        posName = \u0022left flank\u0022,\r\n        posOffset = vector(s1 * 3, 0, 0)\r\n    },\r\n    rightFlank = {\r\n        posName = \u0022right flank\u0022,\r\n        posOffset = vector(-s1 * 3, 0, 0)\r\n    },\r\n    leftSupport = {\r\n        posName = \u0022left support\u0022,\r\n        posOffset = vector(s1 * 3, 0, s1 * 3)\r\n    },\r\n    rearSupport = {\r\n        posName = \u0022rear support\u0022,\r\n        posOffset = vector(0, 0, s1 * 3)\r\n    },\r\n    rightSupport = {\r\n        posName = \u0022right support\u0022,\r\n        posOffset = vector(-s1 * 3, 0, s1 * 3)\r\n    },\r\n}\r\n\r\nwingConfigurations = {\r\n    [3] = {\r\n        [1] = \u0022leftFlank\u0022,\r\n        [2] = \u0022rightFlank\u0022\r\n    },\r\n    [4] = {\r\n        [1] = \u0022leftFlank\u0022,\r\n        [2] = \u0022rightFlank\u0022,\r\n        [3] = \u0022rearSupport\u0022\r\n    },\r\n    [5] = {\r\n        [1] = \u0022leftFlank\u0022,\r\n        [2] = \u0022rightFlank\u0022,\r\n        [3] = \u0022leftSupport\u0022,\r\n        [4] = \u0022rightSupport\u0022\r\n    },\r\n    [6] = {\r\n        [1] = \u0022leftFlank\u0022,\r\n        [2] = \u0022rightFlank\u0022,\r\n        [3] = \u0022rearSupport\u0022,\r\n        [4] = \u0022leftSupport\u0022,\r\n        [5] = \u0022rightSupport\u0022\r\n    }\r\n}\r\n\r\nposNames = { \u0022Two\u0022, \u0022Three\u0022, \u0022Four\u0022, \u0022Five\u0022, \u0022Six\u0022 }\r\n\r\nassignedShips = {}\r\n\r\nconfigured = false\r\n\r\n\r\nleader = nil\r\nnameUnassigned = \u0027Epic Wing Token\u0027\r\nnameAssigned = \u0027\\\u0027s Wing\u0027\r\nwingName = \u0027\u0027\r\nconfiguration = 0\r\n\r\ntoolOpen = false\r\n\r\n-- Save self state\r\nfunction onSave()\r\n    local state = {}\r\n    state.configuration = configuration\r\n    state.wingName = wingName\r\n    state.leader = leader\r\n    state.assignedShips = assignedShips\r\n    state.toolOpen = toolOpen\r\n    state.configured = configured\r\n    return JSON.encode(state)\r\nend\r\n\r\n-- Restore self state\r\nfunction onLoad(save_state)\r\n    nameAssigned = self.getName()\r\n    if save_state ~= \u0027\u0027 and save_state ~= \u0027null\u0027 and save_state ~= nil then\r\n        local state = JSON.decode(save_state)\r\n        configuration = state.configuration or 0\r\n        configured = state.configured or false\r\n        wingName = state.wingName or \u0027\u0027\r\n        leader = state.leader\r\n        assignedShips = state.assignedShips or {}\r\n        for _, wingmate in ipairs(assignedShips) do\r\n            local ship = getObjectFromGUID(wingmate.guid)\r\n            if ship then\r\n                ship.addContextMenuItem(\u0022Rejoin wing\u0022, function() rejoin(ship) end, false)\r\n                ship.addContextMenuItem(\u0022Split from wing\u0022, function() split(ship) end, false)\r\n            end\r\n        end\r\n        toolOpen = state.toolOpen or false\r\n    end\r\n    if configured then\r\n        local formWingButton = {\r\n            [\u0027function_owner\u0027] = self,\r\n            [\u0027click_function\u0027] = \u0027SetWing\u0027,\r\n            [\u0027label\u0027] = \u0027Form Wing\u0027,\r\n            [\u0027position\u0027] = { 0, 0.25, 0 },\r\n            [\u0027rotation\u0027] = { 0, 0, 0 },\r\n            [\u0027width\u0027] = 700,\r\n            [\u0027height\u0027] = 200,\r\n            [\u0027font_size\u0027] = 100\r\n        }\r\n        self.createButton(formWingButton)\r\n    else\r\n        SpawnFirstButtons()\r\n    end\r\nend\r\n\r\nfunction SpawnFirstButtons()\r\n    if nameAssigned == \u0027Epic Wing Token\u0027 then\r\n        self.clearButtons()\r\n        local nameWingButton = {\r\n            [\u0027function_owner\u0027] = self,\r\n            [\u0027click_function\u0027] = \u0027nameWingButton\u0027,\r\n            [\u0027label\u0027] =\r\n            \u0027Click to Start\u0027,\r\n            [\u0027position\u0027] = { 0, 0.25, 0 },\r\n            [\u0027rotation\u0027] = { 0, 0, 0 },\r\n            [\u0027width\u0027] = 700,\r\n            [\u0027height\u0027] = 200,\r\n            [\u0027font_size\u0027] = 100\r\n        }\r\n        self.createButton(nameWingButton)\r\n    else\r\n        SpawnLastButtons()\r\n    end\r\nend\r\n\r\nfunction onDrop()\r\n    if toolOpen == true then\r\n        AddWingmate()\r\n    end\r\nend\r\n\r\nfunction SpawnLastButtons()\r\n    self.clearButtons()\r\n    local ResetButton = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027selfReset\u0027,\r\n        [\u0027label\u0027] = \u0027Reset\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 0.8 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 700,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(ResetButton)\r\n    local formWingButton = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetWing\u0027,\r\n        [\u0027label\u0027] = \u0027Form Wing\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 0 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 700,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(formWingButton)\r\n    toolOpen = true\r\n    wingName = self.getName()\r\nend\r\n\r\n-- Unassign the ship\r\nfunction selfReset()\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/models/epic/epic-wing-token-texture.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    assignedShips = {}\r\n    self.clearButtons()\r\n    self.setName(nameUnassigned)\r\n    nameAssigned = nameUnassigned\r\n    self.call(\u0027SpawnFirstButtons\u0027)\r\n    local newSelf = self.reload()\r\nend\r\n\r\n-- assign ships to wing Place token on the ship and press the Left Wing Button\r\n-- Assign on drop near a small base ship\r\n-- Add a wingmate to the wing\r\nfunction AddWingmate()\r\n    --find which position to fill next\r\n    local nearest = Global.call(\u0022API_FindNearestShip\u0022, { object = self, max_distance = 80 })\r\n    leader_ship = getObjectFromGUID(leader)\r\n    if nearest ~= nil then\r\n        if leader == nil then\r\n            printToAll(\u0027Epic wing token assigned to \u0027 .. nearest.getName())\r\n            leader = nearest.getGUID()\r\n            SpawnFirstButtons()\r\n        elseif #assignedShips \u003C 5 then\r\n            if nearest == leader_ship then\r\n                printToAll(\u0022Unable to add \u0022 .. nearest.getName() .. \u0022 to \u0022 .. wingName .. \u0022, it is already in it\u0022)\r\n                return\r\n            end\r\n            for _, assignment in pairs(assignedShips) do\r\n                if getObjectFromGUID(assignment.guid) == nearest then\r\n                    printToAll(\u0022Unable to add \u0022 .. nearest.getName() .. \u0022 to \u0022 .. wingName .. \u0022, it is already in it\u0022)\r\n                    return\r\n                end\r\n            end\r\n            table.insert(assignedShips, { guid = nearest.getGUID(), active = true })\r\n            nearest.addContextMenuItem(\u0022Rejoin wing\u0022, function() rejoin(nearest) end, false)\r\n            nearest.addContextMenuItem(\u0022Split from wing\u0022, function() split(nearest) end, false)\r\n            printToAll(wingName .. \u0027 \u0027 .. posNames[#assignedShips] .. \u0027: assigned to \u0027 .. nearest.getName())\r\n            return\r\n        else\r\n            printToAll(\u0022Unable to add \u0022 .. nearest.getName() .. \u0022 to \u0022 .. wingName .. \u0022, it is already full\u0022)\r\n            return\r\n        end\r\n    end\r\nend\r\n\r\n-------------------------------------------\r\n----Flavor Script for Naming Squadrons----\r\n\r\nfunction nameWingButton()\r\n    self.clearButtons()\r\n\r\n    local SetRedSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetRedSquadron\u0027,\r\n        [\u0027label\u0027] = \u0027Red Squadron\u0027,\r\n        [\u0027position\u0027] = { -2.5, 0.25, 1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetRedSquadron)\r\n    local SetGoldSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetGoldSquadron\u0027,\r\n        [\u0027label\u0027] =\r\n        \u0027Gold Squadron\u0027,\r\n        [\u0027position\u0027] = { -2.5, 0.25, 0 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetGoldSquadron)\r\n    local SetBlueSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetBlueSquadron\u0027,\r\n        [\u0027label\u0027] =\r\n        \u0027Blue Squadron\u0027,\r\n        [\u0027position\u0027] = { -2.5, 0.25, -1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetBlueSquadron)\r\n    local SetGreenSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetGreenSquadron\u0027,\r\n        [\u0027label\u0027] =\r\n        \u0027Green Squadron\u0027,\r\n        [\u0027position\u0027] = { 2.5, 0.25, 1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetGreenSquadron)\r\n    local SetBlackSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetBlackSquadron\u0027,\r\n        [\u0027label\u0027] =\r\n        \u0027Black Squadron\u0027,\r\n        [\u0027position\u0027] = { 2.5, 0.25, 0 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetBlackSquadron)\r\n    local SetWhiteSquadron = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetWhiteSquadron\u0027,\r\n        [\u0027label\u0027] =\r\n        \u0027White Squadron\u0027,\r\n        [\u0027position\u0027] = { 2.5, 0.25, -1 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 900,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(SetWhiteSquadron)\r\nend\r\n\r\nfunction SetRedSquadron()\r\n    wingName = \u0027Red\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/RedSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    local newSelf = self.reload()\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\nend\r\n\r\nfunction SetGoldSquadron()\r\n    wingName = \u0027Gold\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/GoldSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    local newSelf = self.reload()\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\nend\r\n\r\nfunction SetBlueSquadron()\r\n    wingName = \u0027Blue\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/BlueSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\n    local newSelf = self.reload()\r\nend\r\n\r\nfunction SetGreenSquadron()\r\n    wingName = \u0027Green\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/GreenSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\n    local newSelf = self.reload()\r\nend\r\n\r\nfunction SetBlackSquadron()\r\n    wingName = \u0027Black\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/BlackSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\n    local newSelf = self.reload()\r\nend\r\n\r\nfunction SetWhiteSquadron()\r\n    wingName = \u0027White\u0027\r\n    self.setName(wingName)\r\n    local selfParams = self.getCustomObject()\r\n    selfParams.diffuse =\r\n    \u0022{verifycache}https://raw.githubusercontent.com/JohnnyCheese/TTS_X-Wing2.0/master/assets/Items/tools/WhiteSquadron.png\u0022\r\n    self.setCustomObject(selfParams)\r\n    local newSelf = self.reload()\r\n    self.call(\u0027SpawnLastButtons\u0027)\r\nend\r\n\r\nfunction SetWing()\r\n    if not configured then\r\n        if #assignedShips \u003C 2 then\r\n            printToAll(\u0027A Wing needs to have at least 3 ships to form\u0027)\r\n            return\r\n        end\r\n        configured = true\r\n        configuration = #assignedShips \u002B 1\r\n        toolOpen = false\r\n    end\r\n    self.clearButtons()\r\n    WingMateLand(1, true)\r\n    local formWingButton = {\r\n        [\u0027function_owner\u0027] = self,\r\n        [\u0027click_function\u0027] = \u0027SetWing\u0027,\r\n        [\u0027label\u0027] = \u0027Form Wing\u0027,\r\n        [\u0027position\u0027] = { 0, 0.25, 0 },\r\n        [\u0027rotation\u0027] = { 0, 0, 0 },\r\n        [\u0027width\u0027] = 700,\r\n        [\u0027height\u0027] = 200,\r\n        [\u0027font_size\u0027] = 100\r\n    }\r\n    self.createButton(formWingButton)\r\nend\r\n\r\nfunction WingMateLand(index, recursive)\r\n    local ship = getObjectFromGUID(assignedShips[index].guid)\r\n    local wingpos = wingPositions[wingConfigurations[configuration][index]]\r\n    local leader_ship = getObjectFromGUID(leader)\r\n    if ship ~= nil and assignedShips[index].active then\r\n        desiredPos = LocalPos(leader_ship, wingpos.posOffset)\r\n\r\n        local success = Global.call(\u0022epicMoveWingmate\u0022, { ship, desiredPos, leader_ship.getRotation() })\r\n        if not success then\r\n            printToAll(wingpos.posName .. \u0027 needs to break off\u0027) -- Break from wing, and mark for movement after all other wing members have been moved\r\n            assignedShips[index].active = false\r\n        end\r\n    end\r\n    if index \u003C configuration - 1 and recursive then\r\n        if ship ~= nil then\r\n            Wait.condition(function() WingMateLand(index \u002B 1, recursive) end,\r\n                function() return ship.resting and not ship.isSmoothMoving() end)\r\n        else\r\n            WingMateLand(index \u002B 1, recursive)\r\n        end\r\n    end\r\nend\r\n\r\nfunction rejoin(ship)\r\n    for i, shipinfo in pairs(assignedShips) do\r\n        if getObjectFromGUID(shipinfo.guid) == ship then\r\n            assignedShips[i].active = true\r\n            WingMateLand(i, false)\r\n            return\r\n        end\r\n    end\r\nend\r\n\r\nfunction split(ship)\r\n    for i, shipinfo in pairs(assignedShips) do\r\n        if getObjectFromGUID(shipinfo.guid) == ship then\r\n            assignedShips[i].active = false\r\n            return\r\n        end\r\n    end\r\nend\r\n\r\n-------\r\n-- Local Reference function, for spawning items relative to the quick build card\r\nfunction LocalPos(object, position)\r\n    local rot = object.getRotation()\r\n    local lPos = { position[1], position[2], position[3] }\r\n    -- Z-X-Y extrinsic\r\n    local zRot = RotMatrix(\u0027z\u0027, rot[\u0027z\u0027])\r\n    lPos = RotateVector(zRot, lPos)\r\n    local xRot = RotMatrix(\u0027x\u0027, rot[\u0027x\u0027])\r\n    lPos = RotateVector(xRot, lPos)\r\n    local yRot = RotMatrix(\u0027y\u0027, rot[\u0027y\u0027])\r\n    lPos = RotateVector(yRot, lPos)\r\n\r\n    return Vect.Sum(lPos, object.getPosition())\r\nend\r\n\r\nfunction RotMatrix(axis, angDeg)\r\n    local ang = math.rad(angDeg)\r\n    local cs = math.cos\r\n    local sn = math.sin\r\n\r\n    if axis == \u0027x\u0027 then\r\n        return {\r\n            { 1, 0,       0 },\r\n            { 0, cs(ang), -1 * sn(ang) },\r\n            { 0, sn(ang), cs(ang) }\r\n        }\r\n    elseif axis == \u0027y\u0027 then\r\n        return {\r\n            { cs(ang),      0, sn(ang) },\r\n            { 0,            1, 0 },\r\n            { -1 * sn(ang), 0, cs(ang) }\r\n        }\r\n    elseif axis == \u0027z\u0027 then\r\n        return {\r\n            { cs(ang), -1 * sn(ang), 0 },\r\n            { sn(ang), cs(ang),      0 },\r\n            { 0,       0,            1 }\r\n        }\r\n    end\r\nend\r\n\r\n-- Apply given rotation matrix on given vector\r\n-- (multiply matrix and column vector)\r\nfunction RotateVector(rotMat, vect)\r\n    local out = { 0, 0, 0 }\r\n    for i = 1, 3, 1 do\r\n        for j = 1, 3, 1 do\r\n            out[i] = out[i] \u002B rotMat[i][j] * vect[j]\r\n        end\r\n    end\r\n    return out\r\nend\r\n\nend)\n__bundle_register(\u0022TTS_lib.Vector.Vector\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- ~~~~~~\r\n-- Script by dzikakulka\r\n-- Issues, history at: http://github.com/tjakubo2/TTS_lib\r\n--\r\n-- Library for all vector-related operations\r\n-- Description and usage in README.md in this lib folder in repository\r\n-- ~~~~~~\r\n\r\n-- TODO: Many of these now have TTS equivalents.\r\n-- TODO: e.g. Vector.__add(vec1, vec2)\r\n\r\nlocal Vect = {}\r\n\r\nrequire(\u0022TTS_Lib.Util.Math\u0022)\r\n\r\n-- Sum of two vectors (of any size)\r\nVect.Sum = function(vec1, vec2)\r\n    assert(type(vec1) == \u0027table\u0027, \u0027Vect.Sum: arg#1 not a table!\u0027)\r\n    assert(type(vec2) == \u0027table\u0027, \u0027Vect.Sum: arg#2 not a table!\u0027)\r\n    local out = {}\r\n    local k = 1\r\n    while vec1[k] ~= nil and vec2[k] ~= nil do\r\n        out[k] = vec1[k] \u002B vec2[k]\r\n        k = k \u002B 1\r\n    end\r\n    return out\r\nend\r\n\r\n-- Inverse of a vector\r\nVect.Inverse = function(vector)\r\n    assert(type(vector) == \u0027table\u0027, \u0027Vect.Inverse: arg#1 not a table!\u0027)\r\n    local out = {}\r\n    local k = 1\r\n    while vector[k] ~= nil do\r\n        out[k] = 1 / vector[k]\r\n        k = k \u002B 1\r\n    end\r\n    return out\r\nend\r\n\r\n-- Multiply each element of a vector by a factor\r\nVect.Scale = function(vector, factor)\r\n    assert(type(vector) == \u0027table\u0027, \u0027Vect.Scale: arg#1 not a table!\u0027)\r\n    assert(type(factor) == \u0027number\u0027, \u0027Vect.Scale: arg#2 not a number!\u0027)\r\n    local out = {}\r\n    local k = 1\r\n    while vector[k] ~= nil do\r\n        out[k] = vector[k] * factor\r\n        k = k \u002B 1\r\n    end\r\n    return out\r\nend\r\n\r\n-- Multiply each element of a vector by an element from factor vector\r\n-- (element-wise vector multiplication)\r\nVect.ScaleEach = function(vector, factorVec)\r\n    assert(type(vector) == \u0027table\u0027, \u0027Vect.ScaleEach: arg#1 not a table!\u0027)\r\n    assert(type(factorVec) == \u0027table\u0027, \u0027Vect.ScaleEach: arg#2 not a table!\u0027)\r\n    local out = {}\r\n    local k = 1\r\n    while vector[k] ~= nil and factorVec[k] ~= nil do\r\n        out[k] = vector[k] * factorVec[k]\r\n        k = k \u002B 1\r\n    end\r\n    return out\r\nend\r\n\r\n\r\n-- Length of  vector on X-Z plane (ignoring height)\r\nVect.Length = function(vector)\r\n    assert(type(vector) == \u0027table\u0027, \u0027Vect.Length: arg#1 not a table!\u0027)\r\n    return math.sqrt(vector[1] * vector[1] \u002B vector[3] * vector[3])\r\nend\r\n\r\n-- Rotation of a 3D vector over its second element axis, arg in radians\r\n-- Elements past 3rd are copied\r\nVect.RotateRad = function(vector, radRotation)\r\n    assert(type(vector) == \u0027table\u0027, \u0027Vect.RotateRad: arg#1 not a table!\u0027)\r\n    assert(type(radRotation) == \u0027number\u0027, \u0027Vect.RotateRad: arg#2 not a number!\u0027)\r\n    local newX = math.cos(radRotation) * vector[1] \u002B math.sin(radRotation) * vector[3]\r\n    local newZ = math.sin(radRotation) * vector[1] * -1 \u002B math.cos(radRotation) * vector[3]\r\n    local out = { newX, vector[2], newZ }\r\n    local k = 4\r\n    while vector[k] ~= nil do\r\n        table.insert(out, vector[k])\r\n        k = k \u002B 1\r\n    end\r\n    return out\r\nend\r\n\r\n-- Distance between two points\r\n-- Points as vectors or objects (their positions)\r\nVect.Distance = function(pos1, pos2)\r\n    assert(type(pos1) == \u0027table\u0027 or type(pos1) == \u0027userdata\u0027, \u0027Vect.Distance: arg#1 not a table/object!\u0027)\r\n    assert(type(pos2) == \u0027table\u0027 or type(pos2) == \u0027userdata\u0027, \u0027Vect.Distance: arg#2 not a table/object!\u0027)\r\n    if type(pos1) == \u0027userdata\u0027 then\r\n        pos1 = pos1.getPosition()\r\n    end\r\n    if type(pos2) == \u0027userdata\u0027 then\r\n        pos2 = pos2.getPosition()\r\n    end\r\n    return Vect.Length(Vect.Between(pos1, pos2))\r\nend\r\n\r\n-- Print vector elements\r\nVect.Print = function(vec, name)\r\n    assert(type(vec) == \u0027table\u0027, \u0027Vect.Print: arg#1 not a table!\u0027)\r\n    local out = \u0027[\u0027\r\n    if name then\r\n        out = name .. \u0027 =\u003E \u0027 .. out\r\n    end\r\n    local k = 1\r\n    while vec[k] ~= nil do\r\n        out = out .. math.round(vec[k], 3) .. \u0027 : \u0027\r\n        k = k \u002B 1\r\n    end\r\n    out = out:sub(1, -3) .. \u0027]\u0027\r\n    print(out)\r\nend\r\n\r\n-- Dot product\r\nVect.DotProd = function(vec1, vec2)\r\n    assert(type(vec1) == \u0027table\u0027, \u0027Vect.DotProd: arg#1 not a table!\u0027)\r\n    assert(type(vec2) == \u0027table\u0027, \u0027Vect.DotProd: arg#2 not a table!\u0027)\r\n    local sum = 0\r\n    local k = 1\r\n    while vec1[k] ~= nil and vec2[k] ~= nil do\r\n        sum = sum \u002B vec1[k] * vec2[k]\r\n        k = k \u002B 1\r\n    end\r\n    return sum\r\nend\r\n\r\n-- Element-by-element comparison\r\n-- Fails if length uneven\r\nVect.Compare = function(vec1, vec2)\r\n    assert(type(vec1) == \u0027table\u0027, \u0027Vect.Compare: arg#1 not a table!\u0027)\r\n    assert(type(vec2) == \u0027table\u0027, \u0027Vect.Compare: arg#2 not a table!\u0027)\r\n    if #vec1 ~= #vec2 then\r\n        return false\r\n    end\r\n    local k = 1\r\n    while vec1[k] ~= nil and vec2[k] ~= nil do\r\n        if vec1[k] ~= vec2[k] then\r\n            return false\r\n        end\r\n        k = k \u002B 1\r\n    end\r\n    return true\r\nend\r\n\r\n-- Euclidean norm\r\nVect.Norm = function(vec)\r\n    local selfDot = Vect.DotProd(vec, vec)\r\n    return math.sqrt(selfDot)\r\nend\r\n\r\n-- Convert a vector to unit vector in the same direction\r\n-- Return zero vector for zero vector\r\nVect.ToUnit = function(vec)\r\n    if Vect.Norm(vec) == 0 then\r\n        return vec\r\n    end\r\n    return Vect.Scale(vec, 1 / Vect.Norm(vec))\r\nend\r\n\r\n-- Angle between vectors in radians\r\n-- If second argument not provided, calculate typical angle (from [1, 0, 0, ...] )\r\nVect.Angle = function(vec1, vec2)\r\n    if vec2 == nil then\r\n        vec2 = { 1 }\r\n        for k = 2, #vec1, 1 do\r\n            table.insert(vec2, 0)\r\n        end\r\n    end\r\n    return math.acos(Vect.DotProd(vec1, vec2) / (Vect.Norm(vec1) * Vect.Norm(vec2)))\r\nend\r\n\r\n-- Angle between vectors in radians, in plane\r\n-- If second argument not provided, calculate typical angle (from [1, 0, 0, ...] )\r\nVect.Angle2D = function(vec1, vec2)\r\n    if vec2 == nil then\r\n        vec2 = { 1 }\r\n        for k = 2, #vec1, 1 do\r\n            table.insert(vec2, 0)\r\n        end\r\n    end\r\n    return (math.atan2(vec2[3], vec2[1]) - math.atan2(vec1[3], vec1[1]))\r\nend\r\n\r\n-- Same as Vect.Angle but in degrees\r\nVect.AngleDeg = function(vec1, vec2)\r\n    return math.deg(Vect.Angle(vec1, vec2))\r\nend\r\n\r\n-- Same as Vect.Angle2D but in degrees\r\nVect.AngleDeg2D = function(vec1, vec2)\r\n    return math.deg(Vect.Angle2D(vec1, vec2))\r\nend\r\n\r\n-- Vector pointing from one position to another\r\nVect.Between = function(fromVec, toVec)\r\n    return Vect.Sum(toVec, Vect.Scale(fromVec, -1))\r\nend\r\n\r\n-- Vector pointing between two points\r\nVect.Middle = function(p1, p2)\r\n    return Vect.Sum(p1, Vect.Scale(Vect.Between(p1, p2), 0.5))\r\nend\r\n\r\n-- Subtract vector from another\r\nVect.Sub = function(vec1, vec2)\r\n    return Vect.Sum(vec1, Vect.Scale(vec2, -1))\r\nend\r\n\r\n-- Opposite of a vector\r\nVect.Opposite = function(vector)\r\n    return Vect.Scale(vector, -1)\r\nend\r\n\r\n-- Rotation of a 3D vector over its second element axis, arg in degrees\r\n-- Elements past 3rd are copied\r\nVect.RotateDeg = function(vector, degRotation)\r\n    local radRotation = math.rad(degRotation)\r\n    return Vect.RotateRad(vector, radRotation)\r\nend\r\n\r\n-- Scale the vector to have set length\r\n-- Negative \u0022length\u0022 - opposite of set length\r\nVect.SetLength = function(vector, len)\r\n    return Vect.Scale(vector, len / Vect.Length(vector))\r\nend\r\n\r\nreturn Vect\r\n\nend)\n__bundle_register(\u0022TTS_Lib.Util.Math\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- Round to decPlaces decimal places\r\n-- if decPlaces nil round to nearest integer\r\nif not math.round then\r\n    math.round = function(arg, decPlaces)\r\n        decPlaces = decPlaces or 0\r\n        if decPlaces == 0 then\r\n            return math.floor(arg \u002B 0.5)\r\n        end\r\n        local mult = 10 ^ decPlaces\r\n        return math.floor(arg * mult \u002B 0.5) / mult\r\n    end\r\nend\r\n\r\n-- Return value limited by min and max bounds\r\nif not math.clamp then\r\n    math.clamp = function(var, min, max)\r\n        return (var \u003C min and min) or (var \u003E max and max) or var\r\n    end\r\nend\r\n\r\n-- Sign function, zero for zero\r\nif not math.sgn then\r\n    math.sgn = function(arg)\r\n        return arg \u003C 0 and -1 or arg \u003E 0 and 1 or 0\r\n    end\r\nend\r\n\r\nreturn math\r\n\nend)\n__bundle_register(\u0022Dim\u0022, function(require, _LOADED, __bundle_register, __bundle_modules)\n-- ~~~~~~\r\n-- Script by dzikakulka\r\n-- Issues, history at: http://github.com/tjakubo2/TTS_xwing\r\n--\r\n-- X-Wing related measurements for TTS\r\n-- ~~~~~~\r\n\r\nlocal Dim = {}\r\n\r\n-- adjusted length = 40mm = 1.4536igu\r\n-- 1mm = 0.03612igu\r\nDim.mm_igu_ratio = 0.03637\r\n\r\n-- 40mm = 1.445igu\r\n-- (s1 length / small base size)\r\n\r\n-- 1mm = 0.036125igu\r\n-- mm_igu_ratio = 0.036125\r\n\r\n-- Millimeter dimensions of ship bases\r\nDim.mm_baseSize = {\r\n    small = 40,\r\n    medium = 60,\r\n    large = 80,\r\n    huge = 80,\r\n    smallBase = 40,\r\n    mediumBase = 60,\r\n    largeBase = 80,\r\n    hugeBase = 80,\r\n    objective = 36,\r\n}\r\n\r\nDim.mm_smallBase = Dim.mm_baseSize.small\r\nDim.mm_mediumBase = Dim.mm_baseSize.medium\r\nDim.mm_largeBase = Dim.mm_baseSize.large\r\n\r\n----------------------------------------\r\n-- Standard X-Wing Maneuver Templates --\r\n----------------------------------------\r\n\r\nDim.XWingTemplates = {\r\n    straight = { 40, 80, 120, 160, 200 }, -- Speed to millimeters\r\n    turn = { 35, 62.5, 90 },              -- Turn Middle Radius (mm)\r\n    bank = { 80, 130, 180 },              -- Bank Middle Radius (mm)\r\n}\r\n\r\n-- Millimeter dimensions for cards\r\nDim.mm_upgrade_width = 41\r\nDim.mm_upgrade_height = 63\r\nDim.mm_pilot_width = 63.5\r\nDim.mm_pilot_height = 88\r\n\r\nDim.mm_ship_scale = vector(0.629, 0.629, 0.629)\r\n\r\nDim.mm_cardSize = {\r\n    upgrade = { width = 41, height = 63 },\r\n    pilot = { width = 63.5, height = 88 }\r\n}\r\n\r\n-- Millimeter dimension for dial cards\r\nDim.mm_dialSize = 54\r\n\r\n-- Convert argument from MILLIMETERS to IN-GAME UNITS\r\nfunction Dim.Convert_mm_igu(millimeters)\r\n    return millimeters * Dim.mm_igu_ratio\r\nend\r\n\r\n-- Convert argument from IN-GAME UNITS to MILLIMETERS\r\nfunction Dim.Convert_igu_mm(in_game_units)\r\n    return in_game_units / Dim.mm_igu_ratio\r\nend\r\n\r\nreturn Dim\r\n\nend)\nreturn __bundle_require(\u0022Epic Wing Token.4cc140.lua\u0022)